/**
 * citas.js - Gestion de citas medicas en el frontend
 *
 * BUGS INTENCIONALES:
 * 1. No valida conflicto de horarios (doble booking)
 * 2. La conversion de hora local a ISO pierde la zona horaria de Ecuador (GMT-5)
 * 3. No verifica que la fecha no sea en el pasado antes de enviar
 * 4. El formulario permite seleccionar doctores sin especialidad
 */

const CitasModule = {
    citasCache: [],
    doctoresCache: [],
    pacientesCache: [],

    async init() {
        await Promise.all([
            this.cargarCitas(),
            this.cargarDoctores(),
            this.cargarPacientes(),
        ]);
        this.setupListeners();
    },

    async cargarCitas() {
        try {
            const citas = await CitasAPI.listar();
            this.citasCache = citas;
            this.renderTabla(citas);
        } catch (error) {
            console.log('Error al cargar citas');
        }
    },

    async cargarDoctores() {
        try {
            this.doctoresCache = await DoctoresAPI.listar();
        } catch (e) { /* silencioso */ }
    },

    async cargarPacientes() {
        try {
            this.pacientesCache = await PacientesAPI.listar();
        } catch (e) { /* silencioso */ }
    },

    renderTabla(citas) {
        const tbody = document.querySelector('#citas-table tbody');
        if (!citas || citas.length === 0) {
            tbody.innerHTML = '<tr><td colspan="6">No hay citas registradas</td></tr>';
            return;
        }

        tbody.innerHTML = citas.map(c => {
            // BUG INTENCIONAL: doctor puede ser null y causa error en render
            const doctorNombre = c.doctor
                ? `${c.doctor.nombre} ${c.doctor.apellido}`
                : 'No asignado';

            return `
                <tr>
                    <td>Paciente #${c.pacienteId}</td>
                    <td>${doctorNombre}</td>
                    <td>${formatDateTime(c.fechaHora)}</td>
                    <td>${c.motivo || '—'}</td>
                    <td><span class="badge badge-${(c.estado || '').toLowerCase()}">${c.estado}</span></td>
                    <td class="actions">
                        <button class="btn-edit" onclick="CitasModule.editarCita(${c.id})">Editar</button>
                        <button class="btn-delete" onclick="CitasModule.eliminarCita(${c.id})">Eliminar</button>
                    </td>
                </tr>
            `;
        }).join('');
    },

    setupListeners() {
        document.getElementById('btn-nueva-cita').onclick = () => this.mostrarFormulario();
        document.getElementById('cita-form').onsubmit = (e) => this.guardarCita(e);
        document.getElementById('filter-estado-citas').onchange = (e) => this.filtrarPorEstado(e.target.value);
    },

    async filtrarPorEstado(estado) {
        if (!estado) {
            this.renderTabla(this.citasCache);
            return;
        }
        try {
            const citas = await CitasAPI.porEstado(estado);
            this.renderTabla(citas);
        } catch (e) {
            showAlert('Error al filtrar citas', 'error');
        }
    },

    mostrarFormulario(cita = null) {
        const modal = document.getElementById('modal-cita');
        const form = document.getElementById('cita-form');
        form.reset();

        // Llenar selects
        const selectDoctor = document.getElementById('cita-doctor');
        selectDoctor.innerHTML = '<option value="">Seleccione un doctor</option>' +
            this.doctoresCache.map(d =>
                `<option value="${d.id}">${d.nombre} ${d.apellido} (${d.especialidad || 'Sin esp.'})</option>`
            ).join('');

        const selectPaciente = document.getElementById('cita-paciente');
        selectPaciente.innerHTML = '<option value="">Seleccione un paciente</option>' +
            this.pacientesCache
                .filter(p => p.activo)
                .map(p => `<option value="${p.id}">${p.nombre} ${p.apellido}</option>`)
                .join('');

        if (cita) {
            document.getElementById('cita-id').value = cita.id;
            document.getElementById('cita-paciente').value = cita.pacienteId;
            document.getElementById('cita-doctor').value = cita.doctor?.id || '';
            document.getElementById('cita-fecha-hora').value = cita.fechaHora || '';
            document.getElementById('cita-motivo').value = cita.motivo || '';
            document.getElementById('cita-estado').value = cita.estado || 'PROGRAMADA';
        } else {
            document.getElementById('cita-id').value = '';
        }

        modal.classList.add('show');
    },

    cerrarFormulario() {
        document.getElementById('modal-cita').classList.remove('show');
    },

    async guardarCita(e) {
        e.preventDefault();

        const id = document.getElementById('cita-id').value;
        const fechaLocal = document.getElementById('cita-fecha-hora').value;

        // BUG INTENCIONAL: usa localToISO que no maneja timezone correctamente
        // En Ecuador (GMT-5), la hora se desplaza 5 horas
        const fechaISO = localToISO(fechaLocal);

        const citaData = {
            pacienteId: parseInt(document.getElementById('cita-paciente').value),
            doctorId: parseInt(document.getElementById('cita-doctor').value),
            fechaHora: fechaISO,
            motivo: document.getElementById('cita-motivo').value,
            estado: document.getElementById('cita-estado').value || 'PROGRAMADA',
        };

        // BUG: No verifica conflicto de horarios (doble booking)
        // BUG: No valida que pacienteId y doctorId sean validos
        // BUG: No valida que la fecha sea futura

        try {
            if (id) {
                await CitasAPI.actualizar(parseInt(id), citaData);
                showAlert('Cita actualizada exitosamente', 'success');
            } else {
                await CitasAPI.crear(citaData);
                showAlert('Cita creada exitosamente', 'success');
            }
            this.cerrarFormulario();
            await this.cargarCitas();
        } catch (error) {
            // BUG: mensaje generico
            showAlert('Error al guardar la cita', 'error');
        }
    },

    async editarCita(id) {
        try {
            const cita = await CitasAPI.buscar(id);
            this.mostrarFormulario(cita);
        } catch (error) {
            showAlert('Error al cargar datos de la cita', 'error');
        }
    },

    async eliminarCita(id) {
        try {
            await CitasAPI.eliminar(id);
            showAlert('Cita eliminada exitosamente', 'success');
            await this.cargarCitas();
        } catch (error) {
            showAlert('Error al eliminar cita', 'error');
        }
    },
};

/**
 * doctores.js - Gestion de doctores en el frontend
 *
 * BUGS INTENCIONALES:
 * 1. No valida que especialidad no este vacia
 * 2. La busqueda por especialidad usa endpoint vulnerable (SQLi en backend)
 * 3. No maneja correctamente el caso de doctor sin especialidad en la UI
 */

const DoctoresModule = {
    doctoresCache: [],

    async init() {
        await this.cargarDoctores();
        this.setupListeners();
    },

    async cargarDoctores() {
        try {
            const doctores = await DoctoresAPI.listar();
            this.doctoresCache = doctores;
            this.renderTabla(doctores);
        } catch (error) {
            console.log('Error al cargar doctores');
        }
    },

    renderTabla(doctores) {
        const tbody = document.querySelector('#doctores-table tbody');
        if (!doctores || doctores.length === 0) {
            tbody.innerHTML = '<tr><td colspan="5">No hay doctores registrados</td></tr>';
            return;
        }

        tbody.innerHTML = doctores.map(d => `
            <tr>
                <td>${d.nombre} ${d.apellido}</td>
                <td>${d.especialidad || '<em>Sin especialidad</em>'}</td>
                <td>${d.email || '—'}</td>
                <td>${d.consultorio || '—'}</td>
                <td class="actions">
                    <button class="btn-edit" onclick="DoctoresModule.editarDoctor(${d.id})">Editar</button>
                    <button class="btn-delete" onclick="DoctoresModule.eliminarDoctor(${d.id})">Eliminar</button>
                </td>
            </tr>
        `).join('');
    },

    setupListeners() {
        document.getElementById('btn-nuevo-doctor').onclick = () => this.mostrarFormulario();
        document.getElementById('doctor-form').onsubmit = (e) => this.guardarDoctor(e);

        const searchInput = document.getElementById('search-doctores');
        if (searchInput) {
            // BUG: busqueda sin debounce, igual que pacientes
            searchInput.oninput = async (e) => {
                const query = e.target.value.trim();
                if (query.length > 0) {
                    // BUG: usa el endpoint vulnerable a SQLi sin advertir al usuario
                    const resultados = await DoctoresAPI.buscarPorEspecialidad(query);
                    this.renderTabla(resultados);
                } else {
                    this.renderTabla(this.doctoresCache);
                }
            };
        }
    },

    mostrarFormulario(doctor = null) {
        const modal = document.getElementById('modal-doctor');
        const form = document.getElementById('doctor-form');
        form.reset();

        if (doctor) {
            document.getElementById('doctor-id').value = doctor.id;
            document.getElementById('doctor-nombre').value = doctor.nombre || '';
            document.getElementById('doctor-apellido').value = doctor.apellido || '';
            document.getElementById('doctor-especialidad').value = doctor.especialidad || '';
            document.getElementById('doctor-email').value = doctor.email || '';
            document.getElementById('doctor-telefono').value = doctor.telefono || '';
            document.getElementById('doctor-consultorio').value = doctor.consultorio || '';
        } else {
            document.getElementById('doctor-id').value = '';
        }

        modal.classList.add('show');
    },

    cerrarFormulario() {
        document.getElementById('modal-doctor').classList.remove('show');
    },

    async guardarDoctor(e) {
        e.preventDefault();

        const id = document.getElementById('doctor-id').value;

        const doctorData = {
            nombre: document.getElementById('doctor-nombre').value,
            apellido: document.getElementById('doctor-apellido').value,
            especialidad: document.getElementById('doctor-especialidad').value,
            email: document.getElementById('doctor-email').value,
            telefono: document.getElementById('doctor-telefono').value,
            consultorio: document.getElementById('doctor-consultorio').value,
        };

        // BUG: No valida especialidad (puede guardar vacio)
        // BUG: No valida email
        // BUG: No valida nombre/apellido no vacios

        try {
            if (id) {
                await DoctoresAPI.actualizar(parseInt(id), doctorData);
                showAlert('Doctor actualizado exitosamente', 'success');
            } else {
                await DoctoresAPI.crear(doctorData);
                showAlert('Doctor creado exitosamente', 'success');
            }
            this.cerrarFormulario();
            await this.cargarDoctores();
        } catch (error) {
            showAlert('Error al guardar el doctor', 'error');
        }
    },

    async editarDoctor(id) {
        try {
            const doctor = await DoctoresAPI.buscar(id);
            this.mostrarFormulario(doctor);
        } catch (error) {
            showAlert('Error al cargar datos del doctor', 'error');
        }
    },

    async eliminarDoctor(id) {
        // BUG: no pide confirmacion, elimina directo
        try {
            await DoctoresAPI.eliminar(id);
            showAlert('Doctor eliminado exitosamente', 'success');
            await this.cargarDoctores();
        } catch (error) {
            showAlert('Error al eliminar doctor', 'error');
        }
    },
};

/**
 * historias.js - Gestion de historias clinicas en el frontend
 *
 * BUGS INTENCIONALES:
 * 1. Permite insertar HTML/scripts en el diagnostico (XSS almacenado)
 * 2. No sanitiza los datos que vienen del backend antes de mostrarlos
 * 3. No valida que el paciente exista antes de buscar sus historias
 */

const HistoriasModule = {
    historiasCache: [],
    pacientesCache: [],
    doctoresCache: [],

    async init() {
        await Promise.all([
            this.cargarHistorias(),
            this.cargarPacientes(),
            this.cargarDoctores(),
        ]);
        this.setupListeners();
    },

    async cargarHistorias() {
        try {
            const historias = await HistoriasAPI.listar();
            this.historiasCache = historias;
            this.renderTabla(historias);
        } catch (error) {
            console.log('Error al cargar historias clinicas');
        }
    },

    async cargarPacientes() {
        try {
            this.pacientesCache = await PacientesAPI.listar();
        } catch (e) { /* silencioso */ }
    },

    async cargarDoctores() {
        try {
            this.doctoresCache = await DoctoresAPI.listar();
        } catch (e) { /* silencioso */ }
    },

    renderTabla(historias) {
        const tbody = document.querySelector('#historias-table tbody');
        if (!historias || historias.length === 0) {
            tbody.innerHTML = '<tr><td colspan="5">No hay historias clinicas registradas</td></tr>';
            return;
        }

        tbody.innerHTML = historias.map(h => {
            // BUG: Acceso a propiedades anidadas sin verificacion de null
            const pacienteNombre = h.paciente
                ? `${h.paciente.nombre} ${h.paciente.apellido}`
                : 'N/A';
            const doctorNombre = h.doctor
                ? `${h.doctor.nombre} ${h.doctor.apellido}`
                : 'N/A';

            return `
                <tr>
                    <td>${pacienteNombre}</td>
                    <td>${doctorNombre}</td>
                    <td>${formatDateTime(h.fechaCreacion)}</td>
                    <!-- BUG INTENCIONAL: diagnostico puede contener HTML/scripts (XSS) -->
                    <td>${h.diagnostico}</td>
                    <td class="actions">
                        <button class="btn-view" onclick="HistoriasModule.verHistoria(${h.id})">Ver</button>
                    </td>
                </tr>
            `;
        }).join('');
    },

    setupListeners() {
        document.getElementById('btn-nueva-historia').onclick = () => this.mostrarFormulario();
        document.getElementById('historia-form').onsubmit = (e) => this.guardarHistoria(e);
    },

    mostrarFormulario() {
        const modal = document.getElementById('modal-historia');
        const form = document.getElementById('historia-form');
        form.reset();

        // Llenar select de pacientes
        const selectPaciente = document.getElementById('historia-paciente');
        selectPaciente.innerHTML = '<option value="">Seleccione un paciente</option>' +
            this.pacientesCache.map(p =>
                `<option value="${p.id}">${p.nombre} ${p.apellido}</option>`
            ).join('');

        // Llenar select de doctores
        const selectDoctor = document.getElementById('historia-doctor');
        selectDoctor.innerHTML = '<option value="">Seleccione un doctor (opcional)</option>' +
            this.doctoresCache.map(d =>
                `<option value="${d.id}">${d.nombre} ${d.apellido}</option>`
            ).join('');

        modal.classList.add('show');
    },

    cerrarFormulario() {
        document.getElementById('modal-historia').classList.remove('show');
    },

    async guardarHistoria(e) {
        e.preventDefault();

        const historiaData = {
            pacienteId: parseInt(document.getElementById('historia-paciente').value),
            doctorId: document.getElementById('historia-doctor').value
                ? parseInt(document.getElementById('historia-doctor').value)
                : null,
            diagnostico: document.getElementById('historia-diagnostico').value,
            tratamiento: document.getElementById('historia-tratamiento').value,
            observaciones: document.getElementById('historia-observaciones').value,
        };

        // BUG INTENCIONAL: No sanitiza el diagnostico, permitiendo XSS almacenado
        // Un usuario malicioso puede ingresar: <script>alert('XSS')</script>
        // como diagnostico y se ejecutara al renderizar

        try {
            await HistoriasAPI.crear(historiaData);
            showAlert('Historia clinica creada exitosamente', 'success');
            this.cerrarFormulario();
            await this.cargarHistorias();
        } catch (error) {
            showAlert('Error al guardar la historia clinica', 'error');
        }
    },

    async verHistoria(id) {
        try {
            const h = await HistoriasAPI.buscar(id);
            // BUG INTENCIONAL: innerHTML con datos del backend sin sanitizar (XSS)
            const detalle = `
                <div style="text-align:left">
                    <p><strong>Paciente:</strong> ${h.paciente?.nombre || 'N/A'} ${h.paciente?.apellido || ''}</p>
                    <p><strong>Doctor:</strong> ${h.doctor?.nombre || 'N/A'} ${h.doctor?.apellido || ''}</p>
                    <p><strong>Fecha:</strong> ${formatDateTime(h.fechaCreacion)}</p>
                    <p><strong>Diagnostico:</strong> ${h.diagnostico}</p>
                    <p><strong>Tratamiento:</strong> ${h.tratamiento || 'No especificado'}</p>
                    <p><strong>Observaciones:</strong> ${h.observaciones || 'Ninguna'}</p>
                </div>
            `;

            // BUG: Crea un div con innerHTML para mostrar el detalle (XSS)
            const modal = document.getElementById('modal-historia');
            const detailDiv = document.createElement('div');
            detailDiv.innerHTML = detalle;
            detailDiv.style.padding = '1rem';

            // Remueve el form y muestra detalle
            const form = document.getElementById('historia-form');
            form.style.display = 'none';
            const existing = modal.querySelector('.historia-detalle');
            if (existing) existing.remove();
            detailDiv.className = 'historia-detalle';
            modal.appendChild(detailDiv);

            modal.classList.add('show');
        } catch (error) {
            showAlert('Error al cargar historia clinica', 'error');
        }
    },
};

/**
 * pacientes.js - Gestion de pacientes en el frontend
 *
 * BUGS INTENCIONALES:
 * 1. No valida campos antes de enviar al backend
 * 2. Elimina sin confirmacion
 * 3. renderPacientes no maneja tabla vacia
 * 4. usar innerHTML con datos sin escapar completamente (XSS)
 */

const PacientesModule = {
    pacientesCache: [],

    async init() {
        await this.cargarPacientes();
        this.setupListeners();
        await this.cargarEstadisticas();
    },

    async cargarPacientes() {
        try {
            const pacientes = await PacientesAPI.listar();
            this.pacientesCache = pacientes;
            this.renderTabla(pacientes);
        } catch (error) {
            // BUG INTENCIONAL: No muestra el error al usuario
            console.log('Error al cargar pacientes'); // BUG: console.log en vez de console.error
        }
    },

    async cargarEstadisticas() {
        try {
            const promedio = await PacientesAPI.edadPromedio();
            document.getElementById('stat-edad-promedio').textContent =
                promedio ? promedio.toFixed(1) + ' años' : 'N/D';
        } catch (e) {
            // BUG: traga la excepcion silenciosamente
            document.getElementById('stat-edad-promedio').textContent = '—';
        }
    },

    renderTabla(pacientes) {
        const tbody = document.querySelector('#pacientes-table tbody');
        if (!pacientes || pacientes.length === 0) {
            tbody.innerHTML = '<tr><td colspan="6">No hay pacientes registrados</td></tr>';
            return;
        }

        // BUG INTENCIONAL: usa innerHTML con datos que podrian tener XSS
        // (aunque el backend no sanitiza, el frontend tampoco)
        tbody.innerHTML = pacientes.map(p => `
            <tr>
                <td>${p.nombre} ${p.apellido}</td>
                <td>${p.email || '—'}</td>
                <td>${p.telefono || '—'}</td>
                <td>${formatDate(p.fechaNacimiento)}</td>
                <td><span class="badge ${p.activo ? 'badge-activo' : 'badge-inactivo'}">${p.activo ? 'Activo' : 'Inactivo'}</span></td>
                <td class="actions">
                    <button class="btn-view" onclick="PacientesModule.verPaciente(${p.id})">Ver</button>
                    <button class="btn-edit" onclick="PacientesModule.editarPaciente(${p.id})">Editar</button>
                    <button class="btn-delete" onclick="PacientesModule.eliminarPaciente(${p.id})">Eliminar</button>
                </td>
            </tr>
        `).join('');
    },

    setupListeners() {
        document.getElementById('btn-nuevo-paciente').onclick = () => this.mostrarFormulario();
        document.getElementById('paciente-form').onsubmit = (e) => this.guardarPaciente(e);

        const searchInput = document.getElementById('search-pacientes');
        if (searchInput) {
            // BUG INTENCIONAL: busqueda en tiempo real sin debounce
            // Cada tecla dispara una peticion HTTP
            searchInput.oninput = async (e) => {
                const query = e.target.value.trim();
                if (query.length > 0) {
                    const resultados = await PacientesAPI.buscarPorNombre(query);
                    this.renderTabla(resultados);
                } else {
                    this.renderTabla(this.pacientesCache);
                }
            };
        }
    },

    mostrarFormulario(paciente = null) {
        const modal = document.getElementById('modal-paciente');
        const form = document.getElementById('paciente-form');
        form.reset();

        if (paciente) {
            document.getElementById('paciente-id').value = paciente.id;
            document.getElementById('paciente-nombre').value = paciente.nombre || '';
            document.getElementById('paciente-apellido').value = paciente.apellido || '';
            document.getElementById('paciente-email').value = paciente.email || '';
            document.getElementById('paciente-telefono').value = paciente.telefono || '';
            document.getElementById('paciente-direccion').value = paciente.direccion || '';
            document.getElementById('paciente-fecha-nacimiento').value = paciente.fechaNacimiento || '';
        } else {
            document.getElementById('paciente-id').value = '';
        }

        modal.classList.add('show');
    },

    cerrarFormulario() {
        document.getElementById('modal-paciente').classList.remove('show');
    },

    async guardarPaciente(e) {
        e.preventDefault();

        const id = document.getElementById('paciente-id').value;

        const pacienteData = {
            nombre: document.getElementById('paciente-nombre').value,
            apellido: document.getElementById('paciente-apellido').value,
            email: document.getElementById('paciente-email').value,
            telefono: document.getElementById('paciente-telefono').value,
            direccion: document.getElementById('paciente-direccion').value,
            fechaNacimiento: document.getElementById('paciente-fecha-nacimiento').value,
            activo: true,
        };

        // BUG INTENCIONAL: No valida datos antes de enviar
        // - No verifica que nombre no este vacio
        // - No valida formato de email
        // - No valida formato de telefono
        // - No valida que fecha de nacimiento no sea futura

        try {
            if (id) {
                await PacientesAPI.actualizar(parseInt(id), pacienteData);
                showAlert('Paciente actualizado exitosamente', 'success');
            } else {
                await PacientesAPI.crear(pacienteData);
                showAlert('Paciente creado exitosamente', 'success');
            }
            this.cerrarFormulario();
            await this.cargarPacientes();
            await this.cargarEstadisticas();
        } catch (error) {
            // BUG INTENCIONAL: mensaje de error generico, no muestra detalles
            showAlert('Error al guardar el paciente', 'error');
        }
    },

    async verPaciente(id) {
        try {
            const paciente = await PacientesAPI.buscar(id);
            // BUG: Muestra datos directamente en innerHTML sin escapar
            const info = `
                <strong>Nombre:</strong> ${paciente.nombre} ${paciente.apellido}<br>
                <strong>Email:</strong> ${paciente.email}<br>
                <strong>Telefono:</strong> ${paciente.telefono}<br>
                <strong>Direccion:</strong> ${paciente.direccion || 'N/A'}<br>
                <strong>Fecha Nacimiento:</strong> ${formatDate(paciente.fechaNacimiento)}<br>
                <strong>Estado:</strong> ${paciente.activo ? 'Activo' : 'Inactivo'}
            `;
            alert(info); // BUG: usa alert() que bloquea el UI thread
        } catch (error) {
            showAlert('Error al cargar paciente', 'error');
        }
    },

    async editarPaciente(id) {
        try {
            const paciente = await PacientesAPI.buscar(id);
            this.mostrarFormulario(paciente);
        } catch (error) {
            showAlert('Error al cargar datos del paciente', 'error');
        }
    },

    // BUG INTENCIONAL: Elimina sin pedir confirmacion
    async eliminarPaciente(id) {
        try {
            await PacientesAPI.eliminar(id);
            showAlert('Paciente eliminado exitosamente', 'success');
            await this.cargarPacientes();
        } catch (error) {
            // BUG: Si falla por FK constraint (tiene citas), no se explica bien
            showAlert('Error al eliminar paciente', 'error');
        }
    },
};
